import React, { useState } from 'react';
import { motion } from 'framer-motion';
import { Send, Phone, Video, Search, MapPin } from 'lucide-react';

export default function BarterChat() {
  const [msg, setMsg] = useState("");
  const chats = [
    { id: 1, name: "Sana K.", last: "Is the yoga class still open?", active: true },
    { id: 2, name: "Rahul K.", last: "Thanks for the drill!", active: false }
  ];

  return (
    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="h-[calc(100vh-40px)] m-5 flex bg-white rounded-[40px] border border-slate-100 overflow-hidden shadow-sm">
      <div className="w-80 border-r border-slate-50 flex flex-col">
        <div className="p-8 border-b border-slate-50"><h2 className="text-2xl font-black text-slate-900">Messages</h2></div>
        <div className="flex-1 overflow-y-auto">
          {chats.map(c => (
            <div key={c.id} className={`p-6 flex items-center gap-4 cursor-pointer hover:bg-slate-50 transition-all ${c.active ? 'bg-teal-50 border-r-4 border-teal-600' : ''}`}>
              <div className="w-12 h-12 bg-slate-200 rounded-full" />
              <div><h4 className="font-bold text-slate-900">{c.name}</h4><p className="text-xs text-slate-400 truncate">{c.last}</p></div>
            </div>
          ))}
        </div>
      </div>
      <div className="flex-1 flex flex-col bg-slate-50/30">
        <div className="p-6 bg-white border-b border-slate-100 flex justify-between items-center">
          <div className="flex items-center gap-4"><div className="w-10 h-10 bg-slate-200 rounded-full" /><h3 className="font-bold">Sana K.</h3></div>
          <div className="flex gap-4 text-slate-300"><Phone size={20}/><Video size={20}/></div>
        </div>
        <div className="flex-1 p-8 space-y-4">
          <div className="bg-white p-4 rounded-2xl rounded-tl-none max-w-md shadow-sm text-slate-600 font-medium border border-slate-100">
            Hi! I saw your Yoga listing. Would you like to exchange it for my Python tutoring session?
          </div>
        </div>
        <div className="p-6 bg-white border-t border-slate-100 flex gap-4">
          <input value={msg} onChange={(e) => setMsg(e.target.value)} placeholder="Type a message..." className="flex-1 bg-slate-50 px-6 py-4 rounded-2xl outline-none" />
          <button className="bg-teal-600 text-white p-4 rounded-2xl shadow-lg shadow-teal-600/20"><Send size={20}/></button>
        </div>
      </div>
    </motion.div>
  );
}
